/* Suggested markup: <div class="uiwiki-folding-dot-counter" tabindex="0"><span>Folding Dot Counter</span></div> */
.uiwiki-folding-dot-counter {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-folding-dot-counter > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: folding_dot_counter 1.8s ease-in-out infinite alternate;
}
.uiwiki-folding-dot-counter:hover,
.uiwiki-folding-dot-counter:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes folding_dot_counter {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-folding-dot-counter, .uiwiki-folding-dot-counter > span { animation: none; transition: none; }
}
